import{_ as a,o as s,c as i,a2 as o}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Manual de Diseno de APIs REST","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/apis-rest/01-introduccion-a-rest.md","filePath":"full-stack/arquitectura/apis-rest/01-introduccion-a-rest.md","lastUpdated":1782521464000}'),n={name:"full-stack/arquitectura/apis-rest/01-introduccion-a-rest.md"};function r(t,e,l,c,d,p){return s(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="manual-de-diseno-de-apis-rest" tabindex="-1">Manual de Diseno de APIs REST <a class="header-anchor" href="#manual-de-diseno-de-apis-rest" aria-label="Permalink to &quot;Manual de Diseno de APIs REST&quot;">​</a></h1><p>Una API REST bien disenada no es solo una coleccion de endpoints. Es un contrato entre sistemas, equipos y consumidores que debe ser claro, estable, seguro y operable.</p><h2 id="capitulos-previstos" tabindex="-1">Capitulos previstos <a class="header-anchor" href="#capitulos-previstos" aria-label="Permalink to &quot;Capitulos previstos&quot;">​</a></h2><ol><li><a href="./01-introduccion-a-rest">Introduccion a REST</a></li><li><a href="./02-recursos-rutas-y-metodos">Recursos rutas y metodos</a></li><li><a href="./03-codigos-de-estado-y-errores">Codigos de estado y errores</a></li><li><a href="./04-paginacion-filtros-y-ordenacion">Paginacion filtros y ordenacion</a></li><li><a href="./05-versionado">Versionado</a></li><li><a href="./06-seguridad">Seguridad</a></li><li><a href="./07-documentacion-openapi">Documentacion OpenAPI</a></li><li><a href="./08-buenas-practicas">Buenas practicas</a></li><li><a href="./09-contratos-compatibilidad-y-evolucion">Contratos compatibilidad y evolucion</a></li><li><a href="./10-observabilidad-y-diagnostico">Observabilidad y diagnostico</a></li><li><a href="./11-rendimiento-cache-y-rate-limiting">Rendimiento cache y rate limiting</a></li><li><a href="./12-testing-de-apis-rest">Testing de APIs REST</a></li><li><a href="./13-gobierno-de-apis">Gobierno de APIs</a></li><li><a href="./14-proyecto-final">Proyecto final</a></li></ol><h2 id="que-significa-rest" tabindex="-1">Que significa REST <a class="header-anchor" href="#que-significa-rest" aria-label="Permalink to &quot;Que significa REST&quot;">​</a></h2><p>REST es un estilo arquitectonico basado en recursos, representaciones, identificadores, operaciones uniformes y comunicacion sin estado.</p><p>En la practica, una API REST suele trabajar con:</p><ul><li>Recursos: usuarios, pedidos, productos, facturas.</li><li>URLs: identificadores de recursos.</li><li>Metodos HTTP: GET, POST, PUT, PATCH, DELETE.</li><li>Codigos de estado: 200, 201, 400, 401, 404, 409, 500.</li><li>Representaciones: normalmente JSON.</li></ul><h2 id="objetivos-de-una-buena-api" tabindex="-1">Objetivos de una buena API <a class="header-anchor" href="#objetivos-de-una-buena-api" aria-label="Permalink to &quot;Objetivos de una buena API&quot;">​</a></h2><ul><li>Ser facil de entender.</li><li>Ser consistente.</li><li>Ser segura por defecto.</li><li>Tener errores accionables.</li><li>Evolucionar sin romper clientes.</li><li>Ser observable en produccion.</li><li>Estar documentada como contrato.</li></ul><h2 id="ejemplo-basico" tabindex="-1">Ejemplo basico <a class="header-anchor" href="#ejemplo-basico" aria-label="Permalink to &quot;Ejemplo basico&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET    /orders</span></span>
<span class="line"><span>POST   /orders</span></span>
<span class="line"><span>GET    /orders/{orderId}</span></span>
<span class="line"><span>PATCH  /orders/{orderId}</span></span>
<span class="line"><span>DELETE /orders/{orderId}</span></span></code></pre></div><h2 id="rest-no-es-solo-crud" tabindex="-1">REST no es solo CRUD <a class="header-anchor" href="#rest-no-es-solo-crud" aria-label="Permalink to &quot;REST no es solo CRUD&quot;">​</a></h2><p>Muchas APIs empiezan como CRUD, pero los sistemas reales tienen acciones de negocio:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /orders/{orderId}/confirm</span></span>
<span class="line"><span>POST /invoices/{invoiceId}/send</span></span>
<span class="line"><span>POST /subscriptions/{subscriptionId}/cancel</span></span></code></pre></div><p>Estas rutas pueden ser validas cuando representan transiciones claras del dominio.</p>`,16)])])}const b=a(n,[["render",r]]);export{h as __pageData,b as default};
